#include <cstring>
#include <iostream>

class NamedValue
{
private:
    char* m_name{};
    int m_value{};

public:
    NamedValue(const char* name, int value)
        : m_name{ new char[std::strlen(name) + 1] }
        , m_value{ value }
    {
        std::strcpy(m_name, name);
    }

    NamedValue(const NamedValue& src)
        : m_name{ new char[std::strlen(src.m_name) + 1] }
        , m_value{ src.m_value }
    {
        std::strcpy(m_name, src.m_name);
    }

    NamedValue& operator=(const NamedValue& src)
    {
        if (this == &src)
            return *this;

        delete[] m_name;

        m_name = new char[std::strlen(src.m_name) + 1];
        std::strcpy(m_name, src.m_name);
        m_value = src.m_value;

        return *this;
    }

    ~NamedValue()
    {
        delete[] m_name;
    }

    const char* getName() const { return m_name; }
    int getValue() const { return m_value; }
    void setValue(int v) { m_value = v; }
};

int main()
{
    char name[50]{};
    int val{};
    std::cin >> name >> val;

    NamedValue orig{ name, val };
    NamedValue copy{ orig };

    orig.setValue(val * 2);

    std::cout << copy.getName() << ' ' << copy.getValue() << '\n';
    std::cout << orig.getName() << ' ' << orig.getValue() << '\n';

    return 0;
}
